// src/components/FuelPriceWidget.jsx
import React, { useState, useEffect } from 'react';
import './FuelPriceWidget.css';

// ─── Cities: Delhi · Haryana · UP · Rajasthan ───────────────────────
const CITIES = [
  { label: 'Delhi',     apiName: 'Delhi',     diesel: 87.71, petrol: 96.72 },
  { label: 'Faridabad', apiName: 'Faridabad', diesel: 87.73, petrol: 96.74 },
  { label: 'Gurugram',  apiName: 'Gurugram',  diesel: 87.73, petrol: 96.74 },
  { label: 'Noida',     apiName: 'Noida',     diesel: 87.65, petrol: 96.56 },
  { label: 'Lucknow',   apiName: 'Lucknow',   diesel: 89.82, petrol: 96.57 },
  { label: 'Jaipur',    apiName: 'Jaipur',    diesel: 89.96, petrol: 104.88 },
];

const FUELS = [
  { key: 'Diesel', apiKey: 'diesel', icon: '🛢️', color: '#16a34a', bg: '#f0fdf4' },
  { key: 'Petrol', apiKey: 'petrol', icon: '⛽', color: '#f97316', bg: '#fff7ed' },
];

// ─── Fetch from real API ─────────────────────────────────────────────
const API_BASE = 'https://api.daily-fuel-prices.in/v1/prices';

async function fetchLivePrice(cityName, fuelKey) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 5000); // 5s timeout
  try {
    const res = await fetch(
      `${API_BASE}?city=${encodeURIComponent(cityName)}&fuel=${fuelKey}`,
      { signal: controller.signal }
    );
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();
    // API expected response: { price: 96.72 } or { data: { price: 96.72 } }
    const price = data?.price ?? data?.data?.price ?? null;
    if (price && !isNaN(parseFloat(price))) return parseFloat(price);
    return null;
  } catch {
    return null;
  } finally {
    clearTimeout(timeout);
  }
}

// ─── Fallback: seeded daily variation ───────────────────────────────
function seededRand(seed) {
  const x = Math.sin(seed + 1) * 10000;
  return x - Math.floor(x);
}
function fallbackPrice(base, fuelKey) {
  const d = new Date();
  const seed = d.getFullYear() * 10000 + (d.getMonth() + 1) * 100 + d.getDate()
             + (fuelKey === 'diesel' ? 0 : 999);
  return parseFloat((base + (seededRand(seed) - 0.5) * 0.12).toFixed(2));
}
function fallbackPricePrev(base, fuelKey) {
  const d = new Date(); d.setDate(d.getDate() - 2);
  const seed = d.getFullYear() * 10000 + (d.getMonth() + 1) * 100 + d.getDate()
             + (fuelKey === 'diesel' ? 0 : 999);
  return parseFloat((base + (seededRand(seed) - 0.5) * 0.14).toFixed(2));
}

// ─── Date helpers ────────────────────────────────────────────────────
function todayStr() {
  return new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' });
}
function twoDaysAgoStr() {
  const d = new Date(); d.setDate(d.getDate() - 2);
  return d.toLocaleDateString('en-IN', { day: 'numeric', month: 'short' });
}

// ─── Component ───────────────────────────────────────────────────────
export default function FuelPriceWidget() {
  const [city, setCity] = useState(CITIES[0]);
  const [prices, setPrices] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isLive, setIsLive] = useState(false);
  const [lastUpdated, setLastUpdated] = useState('');

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setPrices(null);

    async function load() {
      // Try live API for both fuels in parallel
      const [liveDiesel, livePetrol] = await Promise.all([
        fetchLivePrice(city.apiName, 'diesel'),
        fetchLivePrice(city.apiName, 'petrol'),
      ]);

      if (cancelled) return;

      const apiWorked = liveDiesel !== null && livePetrol !== null;

      const todayData = {
        Diesel: apiWorked ? liveDiesel : fallbackPrice(city.diesel, 'diesel'),
        Petrol: apiWorked ? livePetrol : fallbackPrice(city.petrol, 'petrol'),
      };
      const prevData = {
        Diesel: fallbackPricePrev(city.diesel, 'diesel'),
        Petrol: fallbackPricePrev(city.petrol, 'petrol'),
      };

      setPrices({ today: todayData, prev: prevData });
      setIsLive(apiWorked);
      setLastUpdated(todayStr());
      setLoading(false);
    }

    load();
    return () => { cancelled = true; };
  }, [city]);

  const trend = (fuel) => {
    if (!prices) return null;
    const d = parseFloat((prices.today[fuel] - prices.prev[fuel]).toFixed(2));
    if (d > 0)  return { color: '#ef4444', arrow: '↑', label: `+₹${Math.abs(d)}` };
    if (d < 0)  return { color: '#16a34a', arrow: '↓', label: `-₹${Math.abs(d)}` };
    return { color: '#6b7280', arrow: '→', label: '—' };
  };

  return (
    <div className="fpw-root">

      {/* Header */}
      <div className="fpw-header">
        <div className="fpw-header-left">
          <span className="fpw-live-dot" />
          <span className="fpw-title">Live Fuel Prices</span>
          {lastUpdated && (
            <span className="fpw-updated">
              {isLive ? '🟢 Live · ' : '📌 Est · '}
              {lastUpdated}
            </span>
          )}
        </div>
        <select
          className="fpw-city-select"
          value={city.label}
          onChange={e => setCity(CITIES.find(c => c.label === e.target.value))}
        >
          {CITIES.map(c => <option key={c.label}>{c.label}</option>)}
        </select>
      </div>

      {/* Price rows */}
      <div className="fpw-body">
        {loading ? (
          <div className="fpw-loading">
            <span className="fpw-spinner" />
            <span>Fetching prices…</span>
          </div>
        ) : (
          FUELS.map(f => {
            const t = trend(f.key);
            return (
              <div key={f.key} className="fpw-row" style={{ '--fc': f.color, '--fb': f.bg }}>
                <div className="fpw-row-left">
                  <span className="fpw-row-icon">{f.icon}</span>
                  <span className="fpw-row-name">{f.key}</span>
                </div>

                <div className="fpw-today">
                  <span className="fpw-today-label">Today</span>
                  <span className="fpw-today-price">₹{prices.today[f.key].toFixed(2)}</span>
                  <span className="fpw-today-unit">/ litre</span>
                </div>

                <div className="fpw-divider" />

                <div className="fpw-past">
                  <span className="fpw-past-label">{twoDaysAgoStr()}</span>
                  <span className="fpw-past-price">₹{prices.prev[f.key].toFixed(2)}</span>
                </div>

                {t && (
                  <div className="fpw-badge" style={{ background: t.color + '18', color: t.color }}>
                    <span className="fpw-badge-arrow">{t.arrow}</span>
                    <span className="fpw-badge-val">{t.label}</span>
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>

      {/* Footer */}
      <div className="fpw-footer">
        <span>
          📍 Prices for <strong>{city.label}</strong> · Incl. VAT &amp; local levies
          {!isLive && !loading && (
            <span style={{ color: '#f97316', marginLeft: 6, fontSize: 11 }}>
              · API unavailable — estimated prices shown
            </span>
          )}
        </span>
      </div>

    </div>
  );
}
